public List<Integer> printReversed(ListNode head) {
    Deque<Integer> stack = new ArrayDeque<>();
    ListNode curr = head;
    while (curr != null) {
        stack.push(curr.val);
        curr = curr.next;
    }
    List<Integer> result = new ArrayList<>();
    while (!stack.isEmpty()) {
        result.add(stack.pop());
    }
    return result;
}

